"""SQL expression evaluator for WHERE and HAVING clauses."""

import re
from typing import Dict
import pandas as pd


class SQLExpressionEvaluator:
    """Evaluates boolean expressions for WHERE and HAVING clauses."""

    def __init__(self, tables: Dict[str, pd.DataFrame]):
        self.tables = tables

    def evaluate(self, expr: str, row: pd.Series) -> bool:
        """Evaluate a boolean expression against a row."""
        if not expr or not expr.strip():
            return True

        expr = self._process_parentheses(expr.strip(), row)
        expr = self._process_not(expr, row)
        expr = self._replace_operators(expr)
        expr = self._handle_like(expr)
        return self._safe_eval(expr, row)

    def _process_parentheses(self, expr: str, row: pd.Series) -> str:
        while '(' in expr:
            start = expr.rfind('(')
            end = expr.find(')', start)
            if end == -1:
                break
            inner = expr[start+1:end]
            result = self.evaluate(inner, row)
            expr = expr[:start] + ('TRUE' if result else 'FALSE') + expr[end+1:]
        return expr

    def _process_not(self, expr: str, row: pd.Series) -> str:
        for match in re.finditer(r'\bNOT\s+(.+?)(?:\s|AND|OR|$)', expr, re.IGNORECASE):
            inner = match.group(1)
            result = self.evaluate(inner, row)
            expr = expr.replace(match.group(0), 'FALSE' if result else 'TRUE')
        return expr

    def _replace_operators(self, expr: str) -> str:
        expr = expr.replace('<>', '!=')
        return expr.replace('AND', 'and').replace('OR', 'or').replace('NOT', 'not') \
                   .replace('TRUE', 'True').replace('FALSE', 'False').replace('NULL', 'None')

    def _handle_like(self, expr: str) -> str:
        def convert_like(match):
            left = match.group(1).strip("'\"")
            pattern = match.group(2).strip("'\"").replace('%', '.*').replace('_', '.')
            return 'True' if re.match(pattern + '$', left, re.IGNORECASE) else 'False'

        return re.sub(
            r"([\"']?[^\"']*?)[\"']?\s+LIKE\s+([\"']?[^\"']*?)[\"']?",
            convert_like, expr, flags=re.IGNORECASE
        )

    def _safe_eval(self, expr: str, row: pd.Series) -> bool:
        def replace_column(match):
            col = match.group(1)
            if '.' in col:
                col = col.split('.')[-1]
            if col in row.index:
                val = row[col]
                if pd.isna(val):
                    return 'None'
                if isinstance(val, str):
                    return f"'{val}'"
                if isinstance(val, (int, float)):
                    return str(val)
            return 'None'

        expr = re.sub(r'\b(\w+)\b', replace_column, expr)
        try:
            return bool(eval(expr, {"__builtins__": {}}, {}))
        except:
            return False

#!/usr/bin/env python3
"""SQL Query CLI for multiple file formats."""

import argparse
import os
import sys
from pathlib import Path

import pandas as pd
from database import CSVDatabase
from query_executor import SQLExecutor


def load_sql_query(sql_arg: str) -> str:
    sql_path = Path(sql_arg)
    if sql_path.exists():
        return sql_path.read_text()
    return sql_arg


def format_as_markdown(df) -> str:
    if df.empty:
        return ""

    headers = list(df.columns)
    lines = ["| " + " | ".join(str(h) for h in headers) + " |",
             "| " + " | ".join(["---"] * len(headers)) + " |"]

    for _, row in df.iterrows():
        cells = ["NULL" if pd.isna(row[col]) else str(row[col]) for col in headers]
        lines.append("| " + " | ".join(cells) + " |")

    return "\n".join(lines)


def save_as_csv(df, output_path: str):
    df.to_csv(output_path, index=False)


def parse_sharded_arg(sharded_str: str) -> tuple:
    """Parse a --sharded argument in the format 'table_name=glob_pattern'."""
    if '=' not in sharded_str:
        raise ValueError(f"Invalid --sharded format: '{sharded_str}'. Expected '<table_name>=<glob_pattern>'")
    table_name, pattern = sharded_str.split('=', 1)
    if not table_name.strip():
        raise ValueError(f"Empty table name in --sharded: '{sharded_str}'")
    if not pattern.strip():
        raise ValueError(f"Empty glob pattern in --sharded: '{sharded_str}'")
    return (table_name.strip(), pattern.strip())


def main():
    parser = argparse.ArgumentParser(description="Run SQL queries on CSV files")
    parser.add_argument('--data', required=True, help='Directory containing CSV files')
    parser.add_argument('--sql', required=True, help='SQL query or path to SQL file')
    parser.add_argument('--out', required=False, help='Output file path for CSV result')
    parser.add_argument('--sharded', action='append', default=[],
                       help='Sharded table definition: <table_name>=<glob_pattern>. Can be specified multiple times.')
    args = parser.parse_args()

    # Validate and parse --sharded arguments
    sharded_configs = []
    for sharded_arg in args.sharded:
        try:
            sharded_configs.append(parse_sharded_arg(sharded_arg))
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)

    if not os.path.isdir(args.data):
        print(f"Error: Data directory '{args.data}' does not exist", file=sys.stderr)
        sys.exit(1)

    try:
        sql = load_sql_query(args.sql)
    except Exception as e:
        print(f"Error loading SQL: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        db = CSVDatabase(args.data)
        # Load sharded tables (these take precedence and can override/add to existing tables)
        if sharded_configs:
            db.load_sharded_tables(sharded_configs)
        if not db.tables:
            print("Error: No valid CSV files found in data directory", file=sys.stderr)
            sys.exit(1)
    except Exception as e:
        print(f"Error loading data: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        result = SQLExecutor(db).execute(sql)
        print(format_as_markdown(result))

        if args.out:
            save_as_csv(result, args.out)
    except Exception as e:
        print(f"Error executing query: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

"""SQL query parser using sqlparse."""

import re
import sqlparse
from sqlparse.sql import Identifier
from sqlparse.tokens import Keyword, Number
from typing import Optional, Tuple, List, Dict, Any


def parse_query(sql: str) -> Dict[str, Any]:
    """Parse SQL into structured query plan."""
    parsed = sqlparse.parse(sql.strip())
    if not parsed:
        raise ValueError("No valid SQL statement found")

    stmt = parsed[0]
    return {
        'select': _extract_select(stmt),
        'from': _extract_from(stmt),
        'where': _extract_where(stmt),
        'group_by': _extract_group_by(stmt),
        'having': _extract_having(stmt),
        'order_by': _extract_order_by(stmt),
        'limit': _extract_limit(stmt),
        'offset': _extract_offset(stmt),
    }


def _extract_clause(stmt, clause_name: str, stop_keywords: List[str]) -> str:
    """Extract a clause expression by name."""
    in_clause = False
    clause_parts = []

    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == clause_name:
                in_clause = True
                continue
            elif token.value.upper() in stop_keywords:
                in_clause = False

        if in_clause and token.value.strip():
            clause_parts.append(token.value)

    return ' '.join(clause_parts).strip()


def _extract_keywords_list(stmt, keyword: str, stop_keywords: List[str]) -> List[str]:
    """Extract a list of items from a keyword clause."""
    items = []
    in_list = False

    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == keyword:
                in_list = True
                continue
            elif token.value.upper() in stop_keywords:
                in_list = False

        if in_list and token.value.strip() and token.value.strip() != ',':
            items.append(token.value.strip())

    return items


def _extract_number_clause(stmt, keyword: str, stop_keywords: List[str]) -> Optional[int]:
    """Extract a numeric value from a clause."""
    in_clause = False

    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == keyword:
                in_clause = True
                continue
            elif token.value.upper() in stop_keywords:
                in_clause = False

        if in_clause and token.value.strip():
            # Try to parse as number
            try:
                val = token.value.strip()
                if val.isdigit() or (val.startswith('-') and val[1:].isdigit()):
                    return int(val)
            except (ValueError, AttributeError):
                pass

    return None


def _extract_select(stmt) -> Tuple[List[str], bool]:
    """Extract SELECT clause expressions and DISTINCT flag."""
    select_exprs = []
    distinct = False
    in_select = False

    for token in stmt.flatten():
        if token.ttype in Keyword and token.value.upper() == 'SELECT':
            in_select = True
            continue
        elif token.ttype in Keyword and token.value.upper() in ['FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
            in_select = False
            continue

        if in_select and token.value.strip():
            val = token.value.strip()
            if val.upper() == 'DISTINCT':
                distinct = True
            else:
                select_exprs.append(val)

    return select_exprs, distinct


def _extract_from(stmt) -> Dict[str, Any]:
    """Extract FROM clause with JOINs."""
    result = {'main_table': None, 'joins': []}
    in_from = False
    in_join = False
    current_join = None
    join_type = 'INNER'

    for token in stmt.tokens:
        if token.ttype in Keyword:
            val = token.value.upper()
            if val == 'FROM':
                in_from = True
                in_join = False
            elif val in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
                join_type = val
            elif val == 'JOIN':
                in_join = True
            elif val == 'ON':
                if current_join:
                    current_join['in_on'] = True
            elif val in ['WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
                in_from = False
                in_join = False
                if current_join:
                    current_join['in_on'] = False

        elif in_from or in_join:
            val = token.value.strip()
            if val and val != ',' and isinstance(token, Identifier):
                table_name = token.get_name()
                if in_join:
                    result['joins'].append({
                        'table': table_name,
                        'type': join_type,
                        'alias': token.get_alias(),
                        'on_cols': []
                    })
                    current_join = result['joins'][-1]
                elif result['main_table'] is None:
                    result['main_table'] = table_name

    return result


def _extract_where(stmt) -> str:
    """Extract WHERE clause expression."""
    return _extract_clause(stmt, 'WHERE', ['GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET'])


def _extract_having(stmt) -> str:
    """Extract HAVING clause expression."""
    return _extract_clause(stmt, 'HAVING', ['ORDER', 'LIMIT', 'OFFSET'])


def _extract_group_by(stmt) -> List[str]:
    """Extract GROUP BY clause."""
    return _extract_keywords_list(stmt, 'GROUP', ['BY', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET'])


def _extract_order_by(stmt) -> List[Tuple[str, bool]]:
    """Extract ORDER BY clause."""
    columns = []
    in_order = False

    for token in stmt.flatten():
        if token.ttype in Keyword and token.value.upper() == 'ORDER':
            in_order = True
            continue
        elif token.ttype in Keyword and token.value.upper() == 'BY':
            continue
        elif token.ttype in Keyword and token.value.upper() in ['LIMIT', 'OFFSET']:
            in_order = False

        if in_order and token.value.strip():
            val = token.value.strip().upper()
            if val == 'DESC':
                if columns:
                    columns[-1] = (columns[-1][0], True)
            elif val == 'ASC':
                if columns:
                    columns[-1] = (columns[-1][0], False)
            elif val != ',':
                columns.append((token.value.strip(), False))

    return columns


def _extract_limit(stmt) -> Optional[int]:
    """Extract LIMIT clause."""
    return _extract_number_clause(stmt, 'LIMIT', ['OFFSET'])


def _extract_offset(stmt) -> Optional[int]:
    """Extract OFFSET clause."""
    return _extract_number_clause(stmt, 'OFFSET', ['LIMIT'])


KEYWORDS = {'AND', 'OR', 'NOT', 'SELECT', 'FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER',
            'LIMIT', 'OFFSET', 'INNER', 'LEFT', 'RIGHT', 'FULL', 'JOIN', 'ON', 'BY', 'ASC', 'DESC'}


def extract_alias(expr: str) -> Optional[str]:
    """Extract alias from expression if present."""
    expr = expr.strip()

    if ' as ' in expr.lower():
        return expr.split('AS')[-1].strip().strip('"').strip("'")

    parts = expr.rsplit(' ', 1)
    if len(parts) == 2:
        potential_alias = parts[1].strip('"').strip("'")
        if potential_alias.upper() not in KEYWORDS:
            try:
                float(potential_alias)
                return None
            except ValueError:
                return potential_alias
    return None


def find_join_key(where_expr: str, table1: str, table2: str) -> Optional[Tuple[str, str]]:
    """Find join key from WHERE or ON clause."""
    if not where_expr:
        return None

    patterns = [
        rf'{table1}\\.(\\w+)\\s*=\\s*{table2}\\.(\\w+)',
        rf'{table2}\\.(\\w+)\\s*=\\s*{table1}\\.(\\w+)',
    ]

    for pattern in patterns:
        match = re.search(pattern, where_expr, re.IGNORECASE)
        if match:
            return (match.group(1), match.group(2))

    return None

"""SQL query executor for CSV data."""

from typing import Dict, List, Optional, Tuple, Any
import pandas as pd

from database import CSVDatabase
from query_parser import parse_query, extract_alias, find_join_key
from evaluator import SQLExpressionEvaluator


class SQLExecutor:
    """Executes SQL queries on CSV data."""

    def __init__(self, db: CSVDatabase):
        self.db = db

    def execute(self, sql: str) -> pd.DataFrame:
        query_plan = parse_query(sql)
        return self._build_query(query_plan)

    def _build_query(self, plan: Dict[str, Any]) -> pd.DataFrame:
        select_list, distinct = plan['select']
        from_clause = plan['from']
        where_expr = plan['where']
        group_by = plan['group_by']
        having_expr = plan['having']
        order_by = plan['order_by']
        limit = plan['limit']
        offset = plan['offset']

        if not from_clause or not from_clause.get('main_table'):
            raise ValueError("FROM clause is required")

        df = self._load_main_table(from_clause['main_table'])
        select_columns = self._process_select_expressions(select_list, df)

        df = self._apply_joins(df, from_clause, where_expr)

        if where_expr:
            df = self._apply_where(df, where_expr)

        if group_by:
            df = self._apply_group_by(df, group_by, select_columns, having_expr, distinct)
        elif having_expr:
            raise ValueError("HAVING clause requires GROUP BY")

        df = self._apply_distinct(df, select_columns, distinct)
        df = self._apply_order_by(df, order_by, select_columns)
        df = self._apply_limit_offset(df, limit, offset)

        return self._build_result(df, select_columns)

    def _load_main_table(self, table_name: str) -> pd.DataFrame:
        df = self.db.get_table(table_name)
        if df is None:
            raise ValueError(f"Table '{table_name}' not found")
        return df.copy()

    def _process_select_expressions(self, select_list: List[str], df: pd.DataFrame) -> List[Tuple[str, str, Optional[str], str]]:
        select_columns = []

        for expr in select_list:
            expr = expr.strip()
            upper = expr.upper()

            if upper.startswith('COUNT('):
                inner = expr[6:-1].strip()
                col = '__count_all__' if inner == '*' else inner.split('.')[-1]
                alias = extract_alias(expr) or f'count_{len(select_columns)}'
                select_columns.append((alias, expr, 'COUNT', col))

            elif upper.startswith('SUM('):
                col = expr[4:-1].strip().split('.')[-1]
                alias = extract_alias(expr) or f'sum_{len(select_columns)}'
                select_columns.append((alias, expr, 'SUM', col))

            elif upper.startswith('MIN('):
                col = expr[4:-1].strip().split('.')[-1]
                alias = extract_alias(expr) or f'min_{len(select_columns)}'
                select_columns.append((alias, expr, 'MIN', col))

            elif upper.startswith('MAX('):
                col = expr[4:-1].strip().split('.')[-1]
                alias = extract_alias(expr) or f'max_{len(select_columns)}'
                select_columns.append((alias, expr, 'MAX', col))

            else:
                col_name = expr.split('.')[-1] if '.' in expr else expr
                alias = extract_alias(expr) or col_name
                select_columns.append((alias, expr, None, col_name))

        return select_columns

    def _apply_joins(self, df: pd.DataFrame, from_clause: Dict, where_expr: str) -> pd.DataFrame:
        for join_info in from_clause.get('joins', []):
            join_df = self.db.get_table(join_info['table'])
            if join_df is None:
                raise ValueError(f"Table '{join_info['table']}' not found")

            join_key = find_join_key(where_expr, from_clause['main_table'], join_info['table'])
            how = (join_info['type'] or 'INNER').upper()

            if join_key:
                df = pd.merge(df, join_df, left_on=join_key[0], right_on=join_key[1],
                             how=how, suffixes=('_x', '_y'))
            else:
                df = pd.merge(df, join_df, how=how, suffixes=('_x', '_y'))

        return df

    def _apply_where(self, df: pd.DataFrame, where_expr: str) -> pd.DataFrame:
        evaluator = SQLExpressionEvaluator(self.db.tables)
        mask = df.apply(lambda row: evaluator.evaluate(where_expr, row), axis=1)
        return df[mask].copy()

    def _apply_group_by(self, df: pd.DataFrame, group_by: List[str],
                       select_columns: List[Tuple], having_expr: str, distinct: bool) -> pd.DataFrame:
        group_cols = [g.split('.')[-1] for g in group_by]
        existing_group_cols = [c for c in group_cols if c in df.columns]

        if not existing_group_cols:
            raise ValueError("No valid GROUP BY columns found")

        agg_dict = {}
        has_count_all = False

        for _, expr, agg_type, col in select_columns:
            if agg_type == 'COUNT' and col == '__count_all__':
                has_count_all = True
            elif agg_type and col in df.columns:
                agg_dict[col] = agg_type.lower()

        if agg_dict:
            grouped = df.groupby(existing_group_cols, as_index=False).agg(agg_dict)
            new_cols = []
            for col in grouped.columns:
                if col in existing_group_cols:
                    new_cols.append(col)
                else:
                    for alias, _, agg_type, c in select_columns:
                        if c == col:
                            new_cols.append(alias)
                            break
                    else:
                        new_cols.append(col)
            grouped.columns = new_cols
            df = grouped

        elif has_count_all:
            df = df.groupby(existing_group_cols, as_index=False).size()
            df.columns = existing_group_cols + ['count']

        else:
            raise ValueError("No valid aggregate in SELECT with GROUP BY")

        if having_expr and group_by:
            evaluator = SQLExpressionEvaluator(self.db.tables)
            mask = df.apply(lambda row: evaluator.evaluate(having_expr, row), axis=1)
            df = df[mask]

        return df

    def _apply_distinct(self, df: pd.DataFrame, select_columns: List[Tuple], distinct: bool) -> pd.DataFrame:
        if distinct:
            select_cols = [alias for alias, _, agg_type, col in select_columns
                         if alias in df.columns and agg_type is None]
            if select_cols:
                df = df[select_cols].drop_duplicates()
        return df

    def _apply_order_by(self, df: pd.DataFrame, order_by: List[Tuple],
                       select_columns: List[Tuple]) -> pd.DataFrame:
        if not order_by:
            return df

        sort_cols = []
        ascending = []

        for col, desc in order_by:
            col_name = col.split('.')[-1]
            if col_name in df.columns:
                sort_cols.append(col_name)
                ascending.append(not desc)
            else:
                for alias, _, _, c in select_columns:
                    if alias == col_name:
                        sort_cols.append(alias)
                        ascending.append(not desc)
                        break

        if sort_cols:
            df = df.sort_values(by=sort_cols, ascending=ascending)
        return df

    def _apply_limit_offset(self, df: pd.DataFrame, limit: Optional[int],
                           offset: Optional[int]) -> pd.DataFrame:
        if limit is not None:
            if offset is not None:
                df = df.iloc[offset:offset+limit]
            else:
                df = df.head(limit)
        elif offset is not None:
            df = df.iloc[offset:]
        return df

    def _build_result(self, df: pd.DataFrame, select_columns: List[Tuple]) -> pd.DataFrame:
        result_cols = []
        for alias, expr, agg_type, col in select_columns:
            if alias in df.columns:
                result_cols.append(alias)
            elif agg_type == 'COUNT' and col == '__count_all__':
                if 'count' in df.columns:
                    result_cols.append('count')

        if not result_cols:
            result_cols = [c for c in df.columns if not c.endswith(('_x', '_y'))]

        return df[result_cols]

"""Database layer for SQL query CLI supporting multiple file formats."""

import sys
from pathlib import Path
from typing import Dict, Optional, Set
import pandas as pd
import gzip
import bz2


class CSVDatabase:
    """Manages multiple file format files as database tables."""

    SUPPORTED_FORMATS = {'.csv', '.parquet', '.tsv', '.json', '.jsonl'}
    COMPRESSED_EXTENSIONS = {'.gz', '.bz2'}

    def __init__(self, data_dir: str):
        self.data_dir = Path(data_dir)
        self.tables: Dict[str, pd.DataFrame] = {}
        self._column_registry: Dict[str, Set[str]] = {}
        self._load_tables()

    def _get_base_filename(self, filepath: Path) -> str:
        name = filepath.name
        for ext in self.COMPRESSED_EXTENSIONS:
            if name.endswith(ext):
                name = name[:-(len(ext))]
                break
        for fmt in self.SUPPORTED_FORMATS:
            if name.endswith(fmt):
                name = name[:-(len(fmt))]
                break
        return name

    def _load_tables(self):
        file_groups: Dict[str, list] = {}

        for ext in self.SUPPORTED_FORMATS:
            for filepath in self.data_dir.rglob(f"*{ext}"):
                base_name = self._get_base_filename(filepath)
                file_groups.setdefault(base_name, []).append((filepath, ext, None))

            for comp_ext in self.COMPRESSED_EXTENSIONS:
                for filepath in self.data_dir.rglob(f"*{ext}{comp_ext}"):
                    base_name = self._get_base_filename(filepath)
                    file_groups.setdefault(base_name, []).append((filepath, ext, comp_ext))

        readers = {
            '.csv': self._read_csv,
            '.parquet': self._read_parquet,
            '.tsv': self._read_tsv,
            '.json': self._read_json,
            '.jsonl': self._read_jsonl,
        }

        for base_name, files in file_groups.items():
            dataframes = []
            table_name = base_name.replace('.', '_')

            for filepath, fmt, comp in files:
                try:
                    df = readers[fmt](filepath, comp)
                    if df is not None and not df.empty and len(df.columns) > 0:
                        dataframes.append(df)
                except Exception as e:
                    print(f"Warning: Could not load {filepath}: {e}", file=sys.stderr)

            if not dataframes:
                continue

            first_cols = set(dataframes[0].columns)
            self._column_registry[table_name] = first_cols

            for i, df in enumerate(dataframes[1:], 1):
                if set(df.columns) != first_cols:
                    print(f"Warning: File {files[i][0].name} has different columns than {files[0][0].name}", file=sys.stderr)
                else:
                    dataframes[0] = pd.concat([dataframes[0], df], ignore_index=True)

            if dataframes[0] is not None:
                self.tables[table_name] = dataframes[0]

    def _open_compressed(self, filepath: Path, comp_ext: Optional[str]):
        if comp_ext == '.gz':
            return gzip.open(filepath, 'rt', encoding='utf-8')
        if comp_ext == '.bz2':
            return bz2.open(filepath, 'rt', encoding='utf-8')
        return open(filepath, 'r', encoding='utf-8')

    def _read_csv(self, filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
        with self._open_compressed(filepath, comp_ext) as f:
            return pd.read_csv(f)

    def _read_parquet(self, filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
        return pd.read_parquet(filepath)

    def _read_tsv(self, filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
        with self._open_compressed(filepath, comp_ext) as f:
            return pd.read_csv(f, sep='\t')

    def _read_json(self, filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
        with self._open_compressed(filepath, comp_ext) as f:
            return pd.read_json(f, lines=False)

    def _read_jsonl(self, filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
        with self._open_compressed(filepath, comp_ext) as f:
            return pd.read_json(f, lines=True)

    def get_table(self, name: str) -> Optional[pd.DataFrame]:
        return self.tables.get(name)

    def get_table_columns(self, name: str) -> Optional[Set[str]]:
        return self._column_registry.get(name)

    def load_sharded_tables(self, sharded_configs: list):
        """Load sharded tables from glob patterns."""
        from glob import glob

        for table_name, pattern in sharded_configs:
            # Find all files matching the glob pattern, sorted lexicographically
            matched_files = sorted(glob(pattern))

            if not matched_files:
                # Create empty table with no schema
                self.tables[table_name] = pd.DataFrame()
                self._column_registry[table_name] = set()
                continue

            # Determine file formats from extensions
            files_with_format = []
            for filepath in matched_files:
                fp = Path(filepath)
                ext = None
                comp_ext = None

                # Check for compression first
