"""Database layer for SQL query CLI supporting multiple file formats."""

import sys
from pathlib import Path
from typing import Dict, Optional
import pandas as pd
import gzip
import bz2


SUPPORTED_FORMATS = {'.csv', '.parquet', '.tsv', '.json', '.jsonl'}
COMPRESSED_EXTENSIONS = {'.gz', '.bz2'}


def _open_compressed(filepath: Path, comp_ext: Optional[str]):
    if comp_ext == '.gz':
        return gzip.open(filepath, 'rt', encoding='utf-8')
    if comp_ext == '.bz2':
        return bz2.open(filepath, 'rt', encoding='utf-8')
    return open(filepath, 'r', encoding='utf-8')


def _read_csv(filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_csv(f)


def _read_parquet(filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
    return pd.read_parquet(filepath)


def _read_tsv(filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_csv(f, sep='\t')


def _read_json(filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_json(f, lines=False)


def _read_jsonl(filepath: Path, comp_ext: Optional[str]) -> pd.DataFrame:
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_json(f, lines=True)


READERS = {
    '.csv': _read_csv,
    '.parquet': _read_parquet,
    '.tsv': _read_tsv,
    '.json': _read_json,
    '.jsonl': _read_jsonl,
}


def _get_base_filename(filepath: Path) -> str:
    name = filepath.name
    for ext in COMPRESSED_EXTENSIONS:
        if name.endswith(ext):
            name = name[:-(len(ext))]
            break
    for fmt in SUPPORTED_FORMATS:
        if name.endswith(fmt):
            name = name[:-(len(fmt))]
            break
    return name


def _find_and_load_files(dir_or_files: Path) -> Dict[str, pd.DataFrame]:
    if isinstance(dir_or_files, (list, tuple)):
        file_paths = [Path(f) for f in dir_or_files]
    else:
        file_paths = list(dir_or_files.rglob(f"*") if dir_or_files.is_dir() else [])
        file_paths = [Path(f) for f in file_paths if not dir_or_files.is_dir()]
        file_paths = [p for p in dir_or_files.rglob("*")] if dir_or_files.is_dir() else list(dir_or_files)

    file_groups: Dict[str, list] = {}

    if isinstance(dir_or_files, Path):
        for ext in SUPPORTED_FORMATS:
            for fp in dir_or_files.rglob(f"*{ext}"):
                base = _get_base_filename(fp)
                name, comp = _get_format_from_path(fp)
                if name:
                    file_groups.setdefault(base, []).append((fp, name, comp))
            for comp_ext in COMPRESSED_EXTENSIONS:
                for fp in dir_or_files.rglob(f"*.csv{comp_ext}") + dir_or_files.rglob(f"*.parquet{comp_ext}"):
                    base = _get_base_filename(fp)
                    name, comp = _get_format_from_path(fp)
                    if name:
                        file_groups.setdefault(base, []).append((fp, name, comp))

    if not file_groups:
        return {}

    tables = {}
    for base_name, files in file_groups.items():
        dataframes = []
        table_name = base_name.replace('.', '_')

        for fp, fmt, comp in files:
            try:
                df = READERS[fmt](fp, comp)
                if df is not None and len(df.columns) > 0:
                    dataframes.append(df)
            except Exception as e:
                print(f"Warning: Could not load {fp}: {e}", file=sys.stderr)

        if not dataframes:
            continue

        first = dataframes[0]
        if len(dataframes) > 1:
            for i, df in enumerate(dataframes[1:], 1):
                if list(df.columns) != list(first.columns):
                    print(f"Warning: File {files[i][0].name} has different columns", file=sys.stderr)
                else:
                    first = pd.concat([first, df], ignore_index=True)

        tables[table_name] = first

    return tables


def _get_format_from_path(filepath: Path) -> tuple[Optional[str], Optional[str]]:
    for comp in COMPRESSED_EXTENSIONS:
        if filepath.name.endswith(comp):
            name_without_comp = filepath.name[:-(len(comp))]
            for fmt in SUPPORTED_FORMATS:
                if name_without_comp.endswith(fmt):
                    return fmt, comp
            return None, None
    for fmt in SUPPORTED_FORMATS:
        if filepath.name.endswith(fmt):
            return fmt, None
    return None, None


class CSVDatabase:
    """Manages multiple file format files as database tables."""

    def __init__(self, data_dir: str):
        self.data_dir = Path(data_dir)
        self.tables: Dict[str, pd.DataFrame] = _find_and_load_files(self.data_dir)

    def get_table(self, name: str) -> Optional[pd.DataFrame]:
        return self.tables.get(name)

    def load_sharded_tables(self, sharded_configs: list):
        for table_name, pattern in sharded_configs:
            from glob import glob
            matched = sorted(glob(pattern))
            if not matched:
                self.tables[table_name] = pd.DataFrame()
                continue

            files_with_fmt = []
            for fp in matched:
                fmt, comp = _get_format_from_path(Path(fp))
                if fmt:
                    files_with_fmt.append((Path(fp), fmt, comp))

            if not files_with_fmt:
                self.tables[table_name] = pd.DataFrame()
                continue

            dataframes = []
            for fp, fmt, comp in files_with_fmt:
                try:
                    df = READERS[fmt](fp, comp)
                    if df is not None and len(df.columns) > 0:
                        dataframes.append(df)
                except Exception as e:
                    print(f"Warning: Could not load {fp}: {e}", file=sys.stderr)

            if not dataframes:
                self.tables[table_name] = pd.DataFrame()
                continue

            first = dataframes[0]
            for i, df in enumerate(dataframes[1:], 1):
                if list(df.columns) != list(first.columns):
                    print(f"Warning: File {files_with_fmt[i][0].name} has different columns", file=sys.stderr)
                else:
                    first = pd.concat([first, df], ignore_index=True)

            self.tables[table_name] = first

